import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.7R1OEGYz.js";const u=JSON.parse('{"title":"Arise recovery","description":"","frontmatter":{},"headers":[],"relativePath":"using/arise.md","filePath":"using/arise.md"}'),r={name:"using/arise.md"};function i(n,e,c,h,l,d){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="arise-recovery" tabindex="-1">Arise recovery <a class="header-anchor" href="#arise-recovery" aria-label="Permalink to &quot;Arise recovery&quot;">​</a></h1><p>Arise recovers a lost device. You rotate to a new passkey with a single-use code. Your address and name stay the same. There is no seed phrase and no support ticket.</p><h2 id="the-flow" tabindex="-1">The flow <a class="header-anchor" href="#the-flow" aria-label="Permalink to &quot;The flow&quot;">​</a></h2><p>The Arise screen is a three-step rail.</p><ol><li><strong>New passkey.</strong> Create a passkey on the new device.</li><li><strong>Request code.</strong> The account requests a recovery code from the issuer.</li><li><strong>Enter code and arise.</strong> Read the code from the <a href="/docs/internals/codes.html">verification service</a>, enter it, and tap Arise.</li></ol><p>When it completes, the account&#39;s passkey is rotated. The old passkey stops working. The new one takes over.</p><p>The screen proves this on the spot. The old passkey fails with a clear message. The new passkey sends normally.</p><p>A full rotation is proven live. <a href="https://sepolia-explorer.giwa.io/tx/0x36770b1bc51c3b6972bb50b5b5d36b65e52121867fc8e1f90d4f254e85676bc3" target="_blank" rel="noreferrer">View the arise transaction.</a></p><h2 id="why-it-is-safe" tabindex="-1">Why it is safe <a class="header-anchor" href="#why-it-is-safe" aria-label="Permalink to &quot;Why it is safe&quot;">​</a></h2><p>The recovery code commits to both the account and the hash of the new key. A code minted for one recovery cannot rotate in any other key or touch any other account.</p><p>Anyone may relay the recovery transaction. The authority is the code itself, not the caller. The lost-device user gets a code, a new passkey, and any relayer can submit. The code is single-use and consumed on chain the moment it verifies.</p><p>If the code expires while the input is open, the button becomes &quot;Request a new code&quot;.</p>',12)])])}const f=t(r,[["render",i]]);export{u as __pageData,f as default};
